import { useState, useRef, useCallback, useEffect } from "react";
import { useLang } from "../../context/LangContext";
import "./ClassifyPage.css";

const API_URL = process.env.REACT_APP_AI_URL;
const STEPS = ["upload", "edit", "loading", "result"];

export default function ClassifyPage() {
  const { lang } = useLang();

  // -------------------------------
  // STATE
  // -------------------------------
  const [step, setStep] = useState("upload");
  const [file, setFile] = useState(null);
  const [preview, setPreview] = useState(null);
  const [naturalSize, setNaturalSize] = useState(null);

  const [adj, setAdj] = useState({ brightness: 1, contrast: 1, color: 1 });
  const [crop, setCrop] = useState(null);
  const [dragging, setDragging] = useState(false);

  const [result, setResult] = useState(null);
  const [error, setError] = useState("");

  const cropAreaRef = useRef(null);
  const startRef = useRef(null);
  const fileInputRef = useRef(null);

  // -------------------------------
  // FILTER (Ó╣üÓĖ¬ÓĖöÓĖćÓĖ£ÓĖźÓĖĀÓĖ▓ÓĖ×ÓĖĢÓĖŁÓĖÖÓ╣üÓĖüÓ╣ēÓ╣äÓĖé)
  // -------------------------------
  const imgFilter = `
    brightness(${adj.brightness})
    contrast(${adj.contrast})
    saturate(${adj.color})
  `;

  // -------------------------------
  // Ó╣ĆÓĖźÓĖĘÓĖŁÓĖüÓĖŻÓĖ╣ÓĖø + ÓĖŁÓ╣łÓĖ▓ÓĖÖÓĖéÓĖÖÓĖ▓ÓĖöÓĖłÓĖŻÓĖ┤ÓĖć
  // -------------------------------
  const handleFile = (f) => {
    if (!f) return;
    setFile(f);
    setError("");
    setResult(null);
    setCrop(null);

    const url = URL.createObjectURL(f);
    setPreview(url);

    const img = new Image();
    img.onload = () =>
      setNaturalSize({ w: img.naturalWidth, h: img.naturalHeight });
    img.src = url;

    setStep("edit");
  };

  // -------------------------------
  // Drag & Drop
  // -------------------------------
  const handleDrop = (e) => {
    e.preventDefault();
    const f = e.dataTransfer.files?.[0];
    if (f) handleFile(f);
  };

  // -------------------------------
  // ÓĖäÓĖ│ÓĖÖÓĖ¦ÓĖōÓĖĢÓĖ│Ó╣üÓĖ½ÓĖÖÓ╣łÓĖć mouse/touch
  // -------------------------------
  const getPos = (e, el) => {
    const rect = el.getBoundingClientRect();
    const touch = e.touches?.[0] ?? e;

    return {
      x: Math.max(0, Math.min(touch.clientX - rect.left, rect.width)),
      y: Math.max(0, Math.min(touch.clientY - rect.top, rect.height)),
    };
  };

  // -------------------------------
  // Ó╣ĆÓĖŻÓĖ┤Ó╣łÓĖĪÓĖźÓĖ▓ÓĖü
  // -------------------------------
  const onStart = (e) => {
    if (!cropAreaRef.current) return;
    e.preventDefault();
    const pos = getPos(e, cropAreaRef.current);

    startRef.current = pos;
    setCrop({ x: pos.x, y: pos.y, x2: pos.x, y2: pos.y });
    setDragging(true);
  };

  // -------------------------------
  // ÓĖźÓĖ▓ÓĖüÓĖŁÓĖóÓĖ╣Ó╣ł
  // -------------------------------
  const onMove = (e) => {
    if (!dragging || !startRef.current || !cropAreaRef.current) return;
    e.preventDefault();

    const pos = getPos(e, cropAreaRef.current);

    setCrop({
      x: Math.min(startRef.current.x, pos.x),
      y: Math.min(startRef.current.y, pos.y),
      x2: Math.max(startRef.current.x, pos.x),
      y2: Math.max(startRef.current.y, pos.y),
    });
  };

  const onEnd = () => setDragging(false);

  const resetCrop = () => {
    setCrop(null);
    startRef.current = null;
  };

  // -------------------------------
  // ÓĖäÓĖ│ÓĖÖÓĖ¦ÓĖō crop ŌåÆ image coordinate
  // -------------------------------
  const toImageCoords = (elW, elH) => {
    if (!crop || !naturalSize) return null;

    const scaleX = naturalSize.w / elW;
    const scaleY = naturalSize.h / elH;

    const w = (crop.x2 - crop.x) * scaleX;
    const h = (crop.y2 - crop.y) * scaleY;

    return {
      x: Math.round(crop.x * scaleX),
      y: Math.round(crop.y * scaleY),
      w: Math.round(w),
      h: Math.round(h),
    };
  };

  // -------------------------------
  // ÓĖ¬Ó╣łÓĖćÓ╣ĆÓĖéÓ╣ēÓĖ▓ AI Backend
  // -------------------------------
  const handleAnalyze = async () => {
    if (!file) return;

    setStep("loading");
    setError("");
    setResult(null);

    const el = cropAreaRef.current;
    const coords =
      el ? toImageCoords(el.clientWidth, el.clientHeight) : null;

    const form = new FormData();
    form.append("file", file);
    form.append("brightness", adj.brightness);
    form.append("contrast", adj.contrast);
    form.append("color", adj.color);

    if (coords) {
      form.append("crop_x", coords.x);
      form.append("crop_y", coords.y);
      form.append("crop_w", coords.w);
      form.append("crop_h", coords.h);
    }

    try {
      const res = await fetch(`${API_URL}/api/ai/classify`, {
        method: "POST",
        body: form,
      });

      const data = await res.json();

      if (data.error) {
        setError(data.error);
        setStep("edit");
        return;
      }

      setResult(data);
      setStep("result");
    } catch {
      setError("Ó╣ĆÓĖŖÓĖĘÓ╣łÓĖŁÓĖĪÓĖĢÓ╣łÓĖŁ server Ó╣äÓĖĪÓ╣łÓ╣äÓĖöÓ╣ē");
      setStep("edit");
    }
  };

  const stepIndex = STEPS.indexOf(step);

  return (
    <div className="cls-wrapper">

      {/* Progress Steps */}
      <div className="cls-steps">
        {[
          lang === "th" ? "ÓĖŁÓĖ▒ÓĖøÓ╣éÓĖ½ÓĖźÓĖö" : "Upload",
          lang === "th" ? "ÓĖøÓĖŻÓĖ▒ÓĖÜÓ╣üÓĖĢÓ╣łÓĖć" : "Edit",
          lang === "th" ? "ÓĖ£ÓĖźÓĖźÓĖ▒ÓĖ×ÓĖśÓ╣ī" : "Result",
        ].map((s, i) => (
          <div
            key={i}
            className={`cls-step ${
              stepIndex > i
                ? "done"
                : stepIndex === i ||
                  (i === 1 && step === "loading")
                ? "active"
                : ""
            }`}
          >
            <div className="cls-step-dot">
              {stepIndex > i ? "Ō£ö" : i + 1}
            </div>
            <span>{s}</span>
          </div>
        ))}
      </div>

      {/* ------------------------- UPLOAD ------------------------- */}
      {step === "upload" && (
        <div className="cls-card">
          <div
            className="cls-dropzone"
            onDrop={handleDrop}
            onDragOver={(e) => e.preventDefault()}
            onClick={() => fileInputRef.current?.click()}
          >
            <p>
              {lang === "th" ? "ÓĖ¦ÓĖ▓ÓĖćÓĖĀÓĖ▓ÓĖ×ÓĖŚÓĖĄÓ╣łÓĖÖÓĖĄÓ╣ł ÓĖ½ÓĖŻÓĖĘÓĖŁ" : "Drop image here, or"}{" "}
              <span className="cls-browse">
                {lang === "th" ? "Ó╣ĆÓĖźÓĖĘÓĖŁÓĖüÓ╣äÓĖ¤ÓĖźÓ╣ī" : "Browse"}
              </span>
            </p>

            <input
              ref={fileInputRef}
              type="file"
              accept="image/*"
              style={{ display: "none" }}
              onChange={(e) => handleFile(e.target.files?.[0])}
            />
          </div>
        </div>
      )}

      {/* ------------------------- EDIT ------------------------- */}
      {step === "edit" && preview && (
        <div className="cls-edit-layout">

          <div className="cls-card">
            <p>
              {lang === "th"
                ? "ÓĖźÓĖ▓ÓĖüÓ╣ĆÓĖ×ÓĖĘÓ╣łÓĖŁÓĖäÓĖŻÓĖŁÓĖøÓĖĀÓĖ▓ÓĖ× ŌĆö ÓĖüÓĖö Reset Ó╣ĆÓĖ×ÓĖĘÓ╣łÓĖŁÓĖźÓ╣ēÓĖ▓ÓĖć"
                : "Drag to crop ŌĆö press Reset to clear"}
            </p>

            <div
              ref={cropAreaRef}
              className="cls-crop-area"
              onMouseDown={onStart}
              onMouseMove={onMove}
              onMouseUp={onEnd}
              onTouchStart={onStart}
              onTouchMove={onMove}
              onTouchEnd={onEnd}
            >
              <img src={preview} style={{ filter: imgFilter }} />

              {crop && (
                <div
                  className="cls-crop-box"
                  style={{
                    left: crop.x,
                    top: crop.y,
                    width: crop.x2 - crop.x,
                    height: crop.y2 - crop.y,
                  }}
                />
              )}
            </div>

            <button onClick={resetCrop}>
              {lang === "th" ? "ÓĖźÓ╣ēÓĖ▓ÓĖćÓĖüÓĖ▓ÓĖŻÓĖäÓĖŻÓĖŁÓĖø" : "Reset crop"}
            </button>

            {error && <p className="cls-error">{error}</p>}
          </div>

          <div className="cls-card">
            <button onClick={handleAnalyze}>
              {lang === "th" ? "ÓĖ¦ÓĖ┤Ó╣ĆÓĖäÓĖŻÓĖ▓ÓĖ░ÓĖ½Ó╣īÓĖĀÓĖ▓ÓĖ×" : "Analyze image"}
            </button>
          </div>
        </div>
      )}

      {/* ------------------------- LOADING ------------------------- */}
      {step === "loading" && (
        <div className="cls-card">
          <p>
            {lang === "th"
              ? "ÓĖüÓĖ│ÓĖźÓĖ▒ÓĖćÓĖ¦ÓĖ┤Ó╣ĆÓĖäÓĖŻÓĖ▓ÓĖ░ÓĖ½Ó╣īÓĖĀÓĖ▓ÓĖ×..."
              : "Analyzing image..."}
          </p>
        </div>
      )}

      {/* ------------------------- RESULT ------------------------- */}
      {step === "result" && result && (
        <div className="cls-card">
          <h2>{lang === "th" ? "ÓĖ£ÓĖźÓĖźÓĖ▒ÓĖ×ÓĖśÓ╣īÓĖ½ÓĖźÓĖ▒ÓĖü" : "Top result"}</h2>

          <p>{result.top?.label}</p>

          <button onClick={() => setStep("edit")}>
            {lang === "th" ? "ÓĖ¦ÓĖ┤Ó╣ĆÓĖäÓĖŻÓĖ▓ÓĖ░ÓĖ½Ó╣īÓ╣āÓĖ½ÓĖĪÓ╣ł" : "Analyze again"}
          </button>

          <button onClick={() => setStep("upload")}>
            {lang === "th" ? "ÓĖĀÓĖ▓ÓĖ×Ó╣āÓĖ½ÓĖĪÓ╣ł" : "New image"}
          </button>
        </div>
      )}
    </div>
  );
}
